{"file_path":"/home/user/workspace/app/admin/catalog/relative-time.tsx","content":"'use client'

import { useEffect, useState } from 'react'

function calc(ts: number): string {
  const seconds = Math.floor((Date.now() - ts) / 1000)
  if (seconds < 60) return 'just now'
  const minutes = Math.floor(seconds / 60)
  if (minutes < 60) return `${minutes}m ago`
  const hours = Math.floor(minutes / 60)
  if (hours < 24) return `${hours}h ago`
  return `${Math.floor(hours / 24)}d ago`
}

/**
 * Renders a relative timestamp (e.g. "3m ago") on the client, updating
 * periodically.  During SSR / prerendering it renders its `dateTime`
 * attribute as fallback text so there is no hydration mismatch.
 */
export function RelativeTime({
  ts,
  dateTime,
  title,
}: {
  ts: number
  /** ISO-8601 date-time string for the `time` element's `dateTime` attribute. */
  dateTime?: string
  /** Tooltip text (absolute timestamp). */
  title?: string
}) {
  const [label, setLabel] = useState<string | null>(null)

  useEffect(() => {
    setLabel(calc(ts))
    const interval = setInterval(() => setLabel(calc(ts)), 30_000)
    return () => clearInterval(interval)
  }, [ts])

  return (
    <time dateTime={dateTime} title={title}>
      {label ?? dateTime ?? ts}
    </time>
  )
}
"}

